/* ══════════════════════════════════════════════════════════════
 * 2. LCD Data Bus — walking-1 test for shorts between D0-D7
 * ══════════════════════════════════════════════════════════ */

static void test_lcd_data_bus(void)
{
    const gpio_num_t d[] = { LCD_D0, LCD_D1, LCD_D2, LCD_D3, LCD_D4, LCD_D5, LCD_D6, LCD_D7 };
    const int n = 8;

    for (int i = 0; i < n; i++) {
        TEST_ASSERT_EQUAL(ESP_OK, cfg_inout(d[i]));
        gpio_set_level(d[i], 0);
    }
    vTaskDelay(pdMS_TO_TICKS(5));

    /* Walk a 1 across the bus, verify neighbors stay LOW */
    for (int i = 0; i < n; i++) {
        gpio_set_level(d[i], 1);
        vTaskDelay(pdMS_TO_TICKS(2));
        if (i > 0)
            TEST_ASSERT_EQUAL_MESSAGE(0, gpio_get_level(d[i-1]),
                "LCD bus short: adjacent lower pin HIGH");
        if (i < n - 1)
            TEST_ASSERT_EQUAL_MESSAGE(0, gpio_get_level(d[i+1]),
                "LCD bus short: adjacent upper pin HIGH");
        gpio_set_level(d[i], 0);
    }
}

/* ══════════════════════════════════════════════════════════════
 * 3. LCD Control — verify CS/RST/DC/WR can toggle
 * ══════════════════════════════════════════════════════════ */

static void test_lcd_control(void)
{
    const gpio_num_t pins[] = { LCD_CS, LCD_RST, LCD_DC, LCD_WR };
    const char *names[] = { "LCD_CS", "LCD_RST", "LCD_DC", "LCD_WR" };
    const int n = 4;

    for (int i = 0; i < n; i++) {
        TEST_ASSERT_EQUAL(ESP_OK, cfg_inout(pins[i]));

        gpio_set_level(pins[i], 1);
        vTaskDelay(pdMS_TO_TICKS(2));
        if (gpio_get_level(pins[i]) != 1)
            TEST_FAIL_MESSAGE("LCD ctrl pin stuck LOW");

        gpio_set_level(pins[i], 0);
        vTaskDelay(pdMS_TO_TICKS(2));
        if (gpio_get_level(pins[i]) != 0)
            TEST_FAIL_MESSAGE("LCD ctrl pin stuck HIGH");

        ESP_LOGI(TAG, "%s OK", names[i]);
    }
}

/* ══════════════════════════════════════════════════════════════
 * 4. SD Card SPI — init bus, send CMD0, verify response
 * ══════════════════════════════════════════════════════════ */

static void test_sd_spi(void)
{
    spi_bus_config_t bus = {
        .mosi_io_num     = SD_MOSI,
        .miso_io_num     = SD_MISO,
        .sclk_io_num     = SD_CLK,
        .quadwp_io_num   = -1,
        .quadhd_io_num   = -1,
        .max_transfer_sz = 4096,
    };
    esp_err_t ret = spi_bus_initialize(SD_SPI_HOST, &bus, SPI_DMA_CH_AUTO);
    TEST_ASSERT_MESSAGE(ret == ESP_OK || ret == ESP_ERR_INVALID_STATE,
        "SPI bus init failed — check MOSI/MISO/CLK GPIOs");

    spi_device_handle_t dev;
    spi_device_interface_config_t devcfg = {
        .clock_speed_hz = 400000,  /* 400 kHz for card init */
        .mode           = 0,
        .spics_io_num   = SD_CS,
        .queue_size     = 1,
    };
    TEST_ASSERT_EQUAL_MESSAGE(ESP_OK, spi_bus_add_device(SD_SPI_HOST, &devcfg, &dev),
        "SPI device add failed");

    /* Send CMD0 (GO_IDLE_STATE) — basic bus connectivity test */
    uint8_t cmd0[6] = {0x40, 0x00, 0x00, 0x00, 0x00, 0x95};
    uint8_t resp[6] = {0};
    spi_transaction_t txn = {
        .length    = 48,
        .tx_buffer = cmd0,
        .rx_buffer = resp,
    };
    TEST_ASSERT_EQUAL_MESSAGE(ESP_OK, spi_device_transmit(dev, &txn),
        "SPI transmit failed — wiring issue");
    ESP_LOGI(TAG, "SD CMD0 response: 0x%02x 0x%02x", resp[0], resp[1]);

    spi_bus_remove_device(dev);
    spi_bus_free(SD_SPI_HOST);
}

/* ══════════════════════════════════════════════════════════════
 * 5. I2S PDM TX — write 100 samples of silence, no error
 * ══════════════════════════════════════════════════════════ */

static void test_i2s_pdm(void)
{
    i2s_chan_handle_t tx = NULL;
    i2s_chan_config_t ch_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    TEST_ASSERT_EQUAL(ESP_OK, i2s_new_channel(&ch_cfg, &tx, NULL));

    i2s_pdm_tx_config_t pdm_cfg = {
        .clk_cfg  = I2S_PDM_TX_CLK_DEFAULT_CONFIG(AUDIO_SAMPLE_RATE),
        .slot_cfg = I2S_PDM_TX_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT,
                                                    I2S_SLOT_MODE_MONO),
        .gpio_cfg = {
            .clk  = I2S_BCLK,
            .dout = I2S_DOUT,
            .invert_flags = { .clk_inv = false },
        },
    };
    TEST_ASSERT_EQUAL(ESP_OK, i2s_channel_init_pdm_tx_channel(tx, &pdm_cfg));
    TEST_ASSERT_EQUAL(ESP_OK, i2s_channel_enable(tx));

    int16_t silence[100] = {0};
    size_t written = 0;
    esp_err_t ret = i2s_channel_write(tx, silence, sizeof(silence),
                                       &written, pdMS_TO_TICKS(500));
    TEST_ASSERT_EQUAL_MESSAGE(ESP_OK, ret, "I2S write error — check BCLK/DOUT wiring");
    TEST_ASSERT_GREATER_THAN_MESSAGE(0, (int)written, "Zero bytes written to I2S");
    ESP_LOGI(TAG, "I2S PDM: %d bytes written OK", (int)written);

    i2s_channel_disable(tx);
    i2s_del_channel(tx);
}

