/* ══════════════════════════════════════════════════════════════
 * 9. PSRAM — allocate 1MB, write/read XOR pattern
 * ══════════════════════════════════════════════════════════ */

#define PSRAM_TEST_SIZE (1024 * 1024)  /* 1 MB */

static void test_psram(void)
{
    uint8_t *buf = heap_caps_malloc(PSRAM_TEST_SIZE, MALLOC_CAP_SPIRAM);
    TEST_ASSERT_NOT_NULL_MESSAGE(buf,
        "Failed to alloc 1MB from PSRAM — check Octal PSRAM config in menuconfig");

    /* Write: each byte = (offset & 0xFF) ^ 0xA5 */
    for (size_t i = 0; i < PSRAM_TEST_SIZE; i++)
        buf[i] = (uint8_t)((i & 0xFF) ^ 0xA5);

    /* Verify */
    int errs = 0;
    for (size_t i = 0; i < PSRAM_TEST_SIZE; i++) {
        uint8_t exp = (uint8_t)((i & 0xFF) ^ 0xA5);
        if (buf[i] != exp) {
            if (errs < 5)
                ESP_LOGE(TAG, "PSRAM @0x%06x: got 0x%02x want 0x%02x",
                         (unsigned)i, buf[i], exp);
            errs++;
        }
    }
    ESP_LOGI(TAG, "PSRAM 1MB check: %d errors", errs);
    TEST_ASSERT_EQUAL_MESSAGE(0, errs, "PSRAM data corruption detected");

    heap_caps_free(buf);
}

